15: Http::Code ListenersHandler::handlerDrainListeners(Http::ResponseHeaderMap&,
16:                                                    Buffer::Instance& response,
17:                                                    AdminStream& admin_query) {
18:   const Http::Utility::QueryParamsMulti params = admin_query.queryParams();
19: 
20:   ListenerManager::StopListenersType stop_listeners_type =
21:       params.getFirstValue("inboundonly").has_value()
22:           ? ListenerManager::StopListenersType::InboundOnly
23:           : ListenerManager::StopListenersType::All;
24: 
25:   const bool graceful = params.getFirstValue("graceful").has_value();
26:   const bool skip_exit = params.getFirstValue("skip_exit").has_value();
27:   if (skip_exit && !graceful) {
28:     response.add("skip_exit requires graceful\n");
29:     return Http::Code::BadRequest;
30:   }
31:   if (graceful) {
32:     auto direction = Network::DrainDirection::All;
33:     if (stop_listeners_type == ListenerManager::StopListenersType::InboundOnly) {
34:       direction = Network::DrainDirection::InboundOnly;
35:     }
36:     // If draining(direction) returns true, it means:
37:     // 1. we are already draining
38:     // 2. That drain includes the direction we're being asked to drain
39:     // We should just return a 200
40:     if (const bool duplicate_drain = server_.drainManager().draining(direction); duplicate_drain) {
41:       response.add("OK\n");
42:       return Http::Code::OK;
43:     }
44:     // This means either we aren't draining or we still have to do some work
45:     // (e.g. we were draining inbound only but now we're being asked to drain all)
46:     server_.drainManager().startDrainSequence(direction, [this, stop_listeners_type, skip_exit]() {
47:       if (!skip_exit) {
48:         server_.listenerManager().stopListeners(stop_listeners_type, {});
49:       }
50:     });
51:   } else {
52:     server_.listenerManager().stopListeners(stop_listeners_type, {});
53:   }
54: 
55:   response.add("OK\n");
56:   return Http::Code::OK;
57: }
58: 
59: Http::Code ListenersHandler::handlerListenerInfo(Http::ResponseHeaderMap& response_headers,
60:                                                  Buffer::Instance& response,
61:                                                  AdminStream& admin_query) {
62:   const Http::Utility::QueryParamsMulti query_params = admin_query.queryParams();
63:   const auto format_value = Utility::formatParam(query_params);
64: 
65:   if (format_value.has_value() && format_value.value() == "json") {
66:     writeListenersAsJson(response);
67:     response_headers.setReferenceContentType(Http::Headers::get().ContentTypeValues.Json);
68:   } else {
69:     writeListenersAsText(response);
70:   }
71:   return Http::Code::OK;
72: }
73: 
74: void ListenersHandler::writeListenersAsJson(Buffer::Instance& response) {
75:   envoy::admin::v3::Listeners listeners;
76:   for (const auto& listener : server_.listenerManager().listeners()) {
77:     envoy::admin::v3::ListenerStatus& listener_status = *listeners.add_listener_statuses();
78:     listener_status.set_name(listener.get().name());
79:     Network::Utility::addressToProtobufAddress(
80:         *listener.get().listenSocketFactories()[0]->localAddress(),
81:         *listener_status.mutable_local_address());
82:     for (std::vector<Network::ListenSocketFactoryPtr>::size_type i = 1;
83:          i < listener.get().listenSocketFactories().size(); i++) {
84:       auto address = listener_status.add_additional_local_addresses();
85:       Network::Utility::addressToProtobufAddress(
86:           *listener.get().listenSocketFactories()[i]->localAddress(), *address);
87:     }
88:   }
89:   response.add(MessageUtil::getJsonStringFromMessageOrError(listeners, true)); // pretty-print
90: }
91: 
92: void ListenersHandler::writeListenersAsText(Buffer::Instance& response) {
93:   for (const auto& listener : server_.listenerManager().listeners()) {
94:     for (auto& socket_factory : listener.get().listenSocketFactories()) {
95:       response.add(fmt::format("{}::{}\n", listener.get().name(),
96:                                socket_factory->localAddress()->asString()));
97:     }
98:   }
99: }
100: 
101: } // namespace Server
102: } // namespace Envoy
