8: AdminFilter::AdminFilter(const Admin& admin) : admin_(admin) {}
9: 
10: Http::FilterHeadersStatus AdminFilter::decodeHeaders(Http::RequestHeaderMap& headers,
11:                                                      bool end_stream) {
12:   request_headers_ = &headers;
13:   if (end_stream) {
14:     onComplete();
15:   }
16: 
17:   return Http::FilterHeadersStatus::StopIteration;
18: }
19: 
20: Http::FilterDataStatus AdminFilter::decodeData(Buffer::Instance& data, bool end_stream) {
21:   // Currently we generically buffer all admin request data in case a handler wants to use it.
22:   // If we ever support streaming admin requests we may need to revisit this. Note, we must use
23:   // addDecodedData() here since we might need to perform onComplete() processing if end_stream is
24:   // true.
25:   decoder_callbacks_->addDecodedData(data, false);
26: 
27:   if (end_stream) {
28:     onComplete();
29:   }
30: 
31:   return Http::FilterDataStatus::StopIterationNoBuffer;
32: }
33: 
34: Http::FilterTrailersStatus AdminFilter::decodeTrailers(Http::RequestTrailerMap&) {
35:   onComplete();
36:   return Http::FilterTrailersStatus::StopIteration;
37: }
38: 
39: void AdminFilter::onDestroy() {
40:   for (const auto& callback : on_destroy_callbacks_) {
41:     callback();
42:   }
43: }
44: 
45: void AdminFilter::addOnDestroyCallback(std::function<void()> cb) {
46:   on_destroy_callbacks_.push_back(std::move(cb));
47: }
48: 
49: Http::StreamDecoderFilterCallbacks& AdminFilter::getDecoderFilterCallbacks() const {
50:   ASSERT(decoder_callbacks_ != nullptr);
51:   return *decoder_callbacks_;
52: }
53: 
54: const Buffer::Instance* AdminFilter::getRequestBody() const {
55:   return decoder_callbacks_->decodingBuffer();
56: }
57: 
58: const Http::RequestHeaderMap& AdminFilter::getRequestHeaders() const {
59:   ASSERT(request_headers_ != nullptr);
60:   return *request_headers_;
61: }
62: 
63: Http::Utility::QueryParamsMulti AdminFilter::queryParams() const {
64:   absl::string_view path = request_headers_->getPathValue();
65:   Http::Utility::QueryParamsMulti query =
66:       Http::Utility::QueryParamsMulti::parseAndDecodeQueryString(path);
67:   if (!query.data().empty()) {
68:     return query;
69:   }
70: 
71:   // Check if the params are in the request's body.
72:   if (request_headers_->getContentTypeValue() ==
73:       Http::Headers::get().ContentTypeValues.FormUrlEncoded) {
74:     const Buffer::Instance* body = getRequestBody();
75:     if (body != nullptr) {
76:       query = Http::Utility::QueryParamsMulti::parseParameters(body->toString(), 0, true);
77:     }
78:   }
79: 
80:   return query;
81: }
82: 
83: void AdminFilter::onComplete() {
84:   absl::string_view path = request_headers_->getPathValue();
85:   ENVOY_STREAM_LOG(debug, "request complete: path: {}", *decoder_callbacks_, path);
86: 
87:   auto header_map = Http::ResponseHeaderMapImpl::create();
88:   RELEASE_ASSERT(request_headers_, "");
89:   Admin::RequestPtr handler = admin_.makeRequest(*this);
90:   Http::Code code = handler->start(*header_map);
91:   Utility::populateFallbackResponseHeaders(code, *header_map);
92:   decoder_callbacks_->encodeHeaders(std::move(header_map), false,
93:                                     StreamInfo::ResponseCodeDetails::get().AdminFilterResponse);
94: 
95:   // TODO(#31087): use high/lower watermarks to apply flow-control to the admin http port.
96:   bool more_data;
97:   do {
98:     Buffer::OwnedImpl response;
99:     more_data = handler->nextChunk(response);
100:     bool end_stream = end_stream_on_complete_ && !more_data;
101:     ENVOY_LOG_MISC(debug, "nextChunk: response.length={} more_data={} end_stream={}",
102:                    response.length(), more_data, end_stream);
103:     if (response.length() > 0 || end_stream) {
104:       decoder_callbacks_->encodeData(response, end_stream);
105:     }
106:   } while (more_data);
107: }
